 1→using System;
 2→using System.IO;
 3→using System.Windows.Forms;
 4→
 5→namespace WeldMonitor3
 6→{
 7→    static class Program
 8→    {
 9→        /// <summary>
10→        /// 해당 응용 프로그램의 주 진입점입니다.
11→        /// </summary>
12→        [STAThread]
13→        static void Main()
14→        {
15→            // 전역 예외 처리
16→            Application.ThreadException += (s, e) =>
17→            {
18→                LogException("ThreadException", e.Exception);
19→                MessageBox.Show(LanguageManager.Get("msg_error_occurred", e.Exception.Message, e.Exception.StackTrace),
20→                    LanguageManager.Get("msg_title_error"), MessageBoxButtons.OK, MessageBoxIcon.Error);
21→            };
22→
23→            AppDomain.CurrentDomain.UnhandledException += (s, e) =>
24→            {
25→                var ex = e.ExceptionObject as Exception;
26→                LogException("UnhandledException", ex);
27→                MessageBox.Show(LanguageManager.Get("msg_fatal_error", ex?.Message, ex?.StackTrace),
28→                    LanguageManager.Get("msg_title_fatal_error"), MessageBoxButtons.OK, MessageBoxIcon.Error);
29→            };
30→
31→            try
32→            {
33→                Application.EnableVisualStyles();
34→                Application.SetCompatibleTextRenderingDefault(false);
35→                Application.Run(new _FrmMain());
36→            }
37→            catch (Exception ex)
38→            {
39→                LogException("Main", ex);
40→                MessageBox.Show(LanguageManager.Get("msg_startup_error", ex.Message, ex.StackTrace),
41→                    LanguageManager.Get("msg_title_startup_error"), MessageBoxButtons.OK, MessageBoxIcon.Error);
42→            }
43→        }
44→
45→        private static void LogException(string source, Exception ex)
46→        {
47→            try
48→            {
49→                string logPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "crash.log");
50→                string logEntry = $"[{DateTime.Now:yyyy-MM-dd HH:mm:ss}] {source}\n{ex?.Message}\n{ex?.StackTrace}\n";
51→                // InnerException 체인 전체 기록
52→                var inner = ex?.InnerException;
53→                while (inner != null)
54→                {
55→                    logEntry += $"  → InnerException: {inner.GetType().Name}: {inner.Message}\n  {inner.StackTrace}\n";
56→                    inner = inner.InnerException;
57→                }
58→                logEntry += "\n";
59→                File.AppendAllText(logPath, logEntry);
60→            }
61→            catch { }
62→        }
63→    }
64→}
